import requests
import json
import sys
import os
from typing import Dict, List, Optional
from requests.auth import HTTPBasicAuth
import urllib.parse


class RabbitMQManager:
    def __init__(self, host: str, port: int, admin_user: str, admin_password: str, use_ssl: bool = False):
        self.protocol = "https" if use_ssl else "http"
        self.base_url = f"{self.protocol}://{host}:{port}/api"
        self.auth = HTTPBasicAuth(admin_user, admin_password)
        self.session = requests.Session()
        self.session.auth = self.auth
        self.session.headers.update({'Content-Type': 'application/json'})
        
        if use_ssl:
            self.session.verify = True

    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        
        try:
            if method == "GET":
                response = self.session.get(url, timeout=10)
            elif method == "PUT":
                response = self.session.put(url, json=data, timeout=10)
            elif method == "POST":
                response = self.session.post(url, json=data, timeout=10)
            elif method == "DELETE":
                response = self.session.delete(url, timeout=10)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {str(e)}", file=sys.stderr)
            raise

    def create_vhost(self, vhost_name: str, description: str = "", tags: str = "") -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        endpoint = f"vhosts/{vhost_encoded}"
        
        data = {}
        if description:
            data['description'] = description
        if tags:
            data['tags'] = tags
        
        response = self._make_request("PUT", endpoint, data)
        
        if response.status_code in [201, 204]:
            print(f"Virtual host '{vhost_name}' created successfully")
            return True
        else:
            print(f"Failed to create vhost '{vhost_name}': {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def delete_vhost(self, vhost_name: str) -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        endpoint = f"vhosts/{vhost_encoded}"
        
        response = self._make_request("DELETE", endpoint)
        
        if response.status_code == 204:
            print(f"Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"Failed to delete vhost '{vhost_name}': {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def list_vhosts(self) -> List[Dict]:
        response = self._make_request("GET", "vhosts")
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"Failed to list vhosts: {response.status_code} - {response.text}", file=sys.stderr)
            return []

    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        endpoint = f"users/{urllib.parse.quote(username, safe='')}"
        
        data = {
            "password": password,
            "tags": tags
        }
        
        response = self._make_request("PUT", endpoint, data)
        
        if response.status_code in [201, 204]:
            print(f"User '{username}' created successfully")
            return True
        else:
            print(f"Failed to create user '{username}': {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def delete_user(self, username: str) -> bool:
        endpoint = f"users/{urllib.parse.quote(username, safe='')}"
        
        response = self._make_request("DELETE", endpoint)
        
        if response.status_code == 204:
            print(f"User '{username}' deleted successfully")
            return True
        else:
            print(f"Failed to delete user '{username}': {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def set_permissions(self, vhost_name: str, username: str, configure: str = ".*", 
                       write: str = ".*", read: str = ".*") -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        user_encoded = urllib.parse.quote(username, safe='')
        endpoint = f"permissions/{vhost_encoded}/{user_encoded}"
        
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        
        response = self._make_request("PUT", endpoint, data)
        
        if response.status_code in [201, 204]:
            print(f"Permissions set for user '{username}' on vhost '{vhost_name}'")
            return True
        else:
            print(f"Failed to set permissions: {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def get_permissions(self, vhost_name: str, username: str) -> Optional[Dict]:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        user_encoded = urllib.parse.quote(username, safe='')
        endpoint = f"permissions/{vhost_encoded}/{user_encoded}"
        
        response = self._make_request("GET", endpoint)
        
        if response.status_code == 200:
            return response.json()
        else:
            return None

    def delete_permissions(self, vhost_name: str, username: str) -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        user_encoded = urllib.parse.quote(username, safe='')
        endpoint = f"permissions/{vhost_encoded}/{user_encoded}"
        
        response = self._make_request("DELETE", endpoint)
        
        if response.status_code == 204:
            print(f"Permissions deleted for user '{username}' on vhost '{vhost_name}'")
            return True
        else:
            print(f"Failed to delete permissions: {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def set_topic_permissions(self, vhost_name: str, username: str, exchange: str,
                             write: str = ".*", read: str = ".*") -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        user_encoded = urllib.parse.quote(username, safe='')
        endpoint = f"topic-permissions/{vhost_encoded}/{user_encoded}"
        
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        
        response = self._make_request("PUT", endpoint, data)
        
        if response.status_code in [201, 204]:
            print(f"Topic permissions set for user '{username}' on vhost '{vhost_name}'")
            return True
        else:
            print(f"Failed to set topic permissions: {response.status_code} - {response.text}", file=sys.stderr)
            return False

    def list_users(self) -> List[Dict]:
        response = self._make_request("GET", "users")
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"Failed to list users: {response.status_code} - {response.text}", file=sys.stderr)
            return []

    def check_health(self) -> bool:
        try:
            response = self._make_request("GET", "overview")
            return response.status_code == 200
        except Exception as e:
            print(f"Health check failed: {str(e)}", file=sys.stderr)
            return False


def setup_multi_tenant_environment(manager: RabbitMQManager, config: Dict):
    print("Starting multi-tenant RabbitMQ setup...")
    
    if not manager.check_health():
        print("RabbitMQ is not healthy. Aborting setup.", file=sys.stderr)
        return False
    
    for tenant in config.get('tenants', []):
        tenant_name = tenant.get('name')
        vhost_name = tenant.get('vhost')
        
        print(f"\nConfiguring tenant: {tenant_name}")
        
        if not manager.create_vhost(vhost_name, description=tenant.get('description', ''), 
                                    tags=tenant.get('tags', '')):
            continue
        
        for user_config in tenant.get('users', []):
            username = user_config.get('username')
            password = user_config.get('password')
            tags = user_config.get('tags', '')
            
            if not username or not password:
                print(f"Skipping user with missing credentials", file=sys.stderr)
                continue
            
            manager.create_user(username, password, tags)
            
            permissions = user_config.get('permissions', {})
            configure = permissions.get('configure', '.*')
            write = permissions.get('write', '.*')
            read = permissions.get('read', '.*')
            
            manager.set_permissions(vhost_name, username, configure, write, read)
            
            topic_permissions = user_config.get('topic_permissions', [])
            for topic_perm in topic_permissions:
                exchange = topic_perm.get('exchange')
                topic_write = topic_perm.get('write', '.*')
                topic_read = topic_perm.get('read', '.*')
                
                if exchange:
                    manager.set_topic_permissions(vhost_name, username, exchange, 
                                                 topic_write, topic_read)
    
    print("\nMulti-tenant setup completed!")
    return True


